**Untested:** `AuthController@login`, `@logout`, `@me`, `@forgotPassword`, `@resetPassword`; `MfaController@verify`

**Missing scenarios:**
- Happy-path login returns token
- Login with wrong credentials returns 401
- Account locked/inactive returns 403
- MFA-required login returns challenge token, no access token
- MFA verify with expired/invalid code
- `forgotPassword` with non-existent email
- `resetPassword` with expired token

```php
// tests/Feature/Auth/AuthControllerTest.php
declare(strict_types=1);
namespace Tests\Feature\Auth;

use App\Models\User;
use Illuminate\Foundation\Testing\RefreshDatabase;
use Tests\TestCase;

class AuthControllerTest extends TestCase
{
    use RefreshDatabase;

    public function test_login_returns_access_token_for_valid_credentials(): void
    {
        $user = User::factory()->create(['password' => bcrypt('Secret!1')]);
        $response = $this->postJson('/api/v1/auth/login', [
            'email' => $user->email, 'password' => 'Secret!1',
        ]);
        $response->assertOk()->assertJsonStructure(['access_token', 'user']);
    }

    public function test_login_returns_401_for_wrong_password(): void
    {
        $user = User::factory()->create(['password' => bcrypt('correct')]);
        $this->postJson('/api/v1/auth/login', ['email' => $user->email, 'password' => 'wrong'])
             ->assertUnauthorized();
    }

    public function test_login_returns_403_for_inactive_account(): void
    {
        $user = User::factory()->create(['status' => 'inactive', 'password' => bcrypt('pw')]);
        $this->postJson('/api/v1/auth/login', ['email' => $user->email, 'password' => 'pw'])
             ->assertForbidden();
    }

    public function test_login_returns_mfa_challenge_when_mfa_enabled(): void
    {
        $user = User::factory()->mfaEnabled()->create(['password' => bcrypt('pw')]);
        $response = $this->postJson('/api/v1/auth/login', ['email' => $user->email, 'password' => 'pw']);
        $response->assertOk()
                 ->assertJsonFragment(['mfa_required' => true])
                 ->assertJsonMissing(['access_token']);
    }

    public function test_me_returns_authenticated_user(): void
    {
        $user = User::factory()->create();
        $this->actingAs($user, 'sanctum')
             ->getJson('/api/v1/auth/me')
             ->assertOk()
             ->assertJsonPath('data.id', $user->id);
    }

    public function test_logout_revokes_token(): void
    {
        $user = User::factory()->create();
        $token = $user->createToken('test')->plainTextToken;
        $this->withToken($token)->postJson('/api/v1/auth/logout')->assertNoContent();
        // token is revoked — next request should 401
        $this->withToken($token)->getJson('/api/v1/auth/me')->assertUnauthorized();
    }

    public function test_forgot_password_returns_ok_for_unknown_email(): void
    {
        // Should not reveal whether email exists
        $this->postJson('/api/v1/auth/forgot-password', ['email' => 'nobody@test.com'])
             ->assertOk();
    }
}
```

