**Untested:** `EmployeeController`, `EmployeeService::create/update/list`, `EmployeeRepository::paginate` (all filter combinations)

**Missing scenarios:**
- Create employee auto-generates User when `create_user = true`
- Paginate with `search`, `department_id`, `position_id`, `status`, `sort`, `direction`
- Filter returns only matching employees
- Soft-delete does not appear in index
- Unique employee number constraint

```php
// tests/Feature/Employee/EmployeeControllerTest.php
declare(strict_types=1);
namespace Tests\Feature\Employee;

use App\Models\Department;
use App\Models\Employee;
use App\Models\Position;
use App\Models\User;
use Illuminate\Foundation\Testing\RefreshDatabase;
use Tests\TestCase;

class EmployeeControllerTest extends TestCase
{
    use RefreshDatabase;

    public function test_index_returns_paginated_employees(): void
    {
        Employee::factory()->count(5)->create();
        $this->actingAsAdmin()->getJson('/api/v1/employees')
             ->assertOk()->assertJsonStructure(['data', 'meta']);
    }

    public function test_index_filters_by_department(): void
    {
        $dept = Department::factory()->create();
        Employee::factory()->for($dept)->count(3)->create();
        Employee::factory()->count(2)->create(); // different dept

        $response = $this->actingAsAdmin()
                         ->getJson("/api/v1/employees?department_id={$dept->id}");
        $response->assertOk();
        $this->assertCount(3, $response->json('data'));
    }

    public function test_index_search_matches_name_and_employee_number(): void
    {
        Employee::factory()->create(['employee_number' => 'EMP-001']);
        Employee::factory()->count(4)->create();

        $response = $this->actingAsAdmin()->getJson('/api/v1/employees?search=EMP-001');
        $response->assertOk();
        $this->assertCount(1, $response->json('data'));
    }

    public function test_store_creates_employee_and_linked_user(): void
    {
        $payload = [
            'first_name' => 'Jane', 'last_name' => 'Doe',
            'email' => 'jane@test.com', 'employee_number' => 'EMP-999',
            'employment_status' => 'regular', 'basic_salary' => 25000,
            'pay_frequency' => 'semi_monthly', 'create_user' => true,
        ];
        $this->actingAsAdmin()->postJson('/api/v1/employees', $payload)
             ->assertCreated()->assertJsonPath('data.employee_number', 'EMP-999');
        $this->assertDatabaseHas('users', ['email' => 'jane@test.com']);
    }

    public function test_store_rejects_duplicate_employee_number(): void
    {
        Employee::factory()->create(['employee_number' => 'EMP-DUP']);
        $this->actingAsAdmin()->postJson('/api/v1/employees', ['employee_number' => 'EMP-DUP'])
             ->assertUnprocessable();
    }

    public function test_destroy_soft_deletes_employee(): void
    {
        $emp = Employee::factory()->create();
        $this->actingAsAdmin()->deleteJson("/api/v1/employees/{$emp->id}")->assertNoContent();
        $this->assertSoftDeleted('employees', ['id' => $emp->id]);
    }
}
