**Untested:** `PayrollRunService` — batch orchestration, per-employee execution, finalization

**Missing scenarios:**
- Run on empty employee set produces zero payslips
- Run skips employees on different pay frequency
- Finalized run cannot be re-run
- Re-running a draft run replaces existing draft payslips

```php
// tests/Feature/Payroll/PayrollRunServiceTest.php
declare(strict_types=1);
namespace Tests\Feature\Payroll;

use App\Models\Employee;
use App\Models\PayrollPeriod;
use App\Services\Payroll\PayrollRunService;
use Database\Seeders\BirTaxBracketSeeder;
use Database\Seeders\PagibigSettingSeeder;
use Database\Seeders\PhilhealthBracketSeeder;
use Database\Seeders\SssBracketSeeder;
use Illuminate\Foundation\Testing\RefreshDatabase;
use Tests\TestCase;

class PayrollRunServiceTest extends TestCase
{
    use RefreshDatabase;

    protected function setUp(): void
    {
        parent::setUp();
        $this->seed([SssBracketSeeder::class, PhilhealthBracketSeeder::class,
                     PagibigSettingSeeder::class, BirTaxBracketSeeder::class]);
    }

    public function test_run_generates_one_payslip_per_employee(): void
    {
        $period = PayrollPeriod::factory()->create(['frequency' => 'monthly', 'status' => 'open']);
        Employee::factory()->count(3)->create(['pay_frequency' => 'monthly', 'basic_salary' => 25000]);

        $run = app(PayrollRunService::class)->execute($period, scope: 'company');

        $this->assertCount(3, $run->payslips);
    }

    public function test_run_skips_employees_on_different_frequency(): void
    {
        $period = PayrollPeriod::factory()->create(['frequency' => 'monthly']);
        Employee::factory()->create(['pay_frequency' => 'monthly', 'basic_salary' => 25000]);
        Employee::factory()->create(['pay_frequency' => 'semi_monthly', 'basic_salary' => 25000]);

        $run = app(PayrollRunService::class)->execute($period, scope: 'company');
        $this->assertCount(1, $run->payslips);
    }

    public function test_finalized_run_cannot_be_reexecuted(): void
    {
        $period = PayrollPeriod::factory()->create(['frequency' => 'monthly', 'status' => 'closed']);
        $run = \App\Models\PayrollRun::factory()->for($period)->create(['status' => 'finalized']);

        $this->expectException(\App\Exceptions\PayrollRunAlreadyFinalizedException::class);
        app(PayrollRunService::class)->execute($period, scope: 'company');
    }
}
