**Missing scenarios in existing `PayrollEngineServiceTest`:**
- Late-minutes deduction
- OT on regular holiday (300% premium)
- OT on rest day (130%/169%)
- Loan deduction carried through payslip items
- Multiple simultaneous allowances + deductions
- `weekly` pay frequency basic computation
- Negative net pay guard (net can't go below zero)

```php
// Additions to PayrollEngineServiceTest.php

public function test_late_minutes_reduce_gross(): void
{
    $employee = $this->makeEmployee(26000, 'monthly'); // ₱125/hr → ₱2.083/min
    $inputs = new PayrollInputs(lateMinutes: 60); // 1 hour late
    $result = $this->engine->computeForEmployee($employee, $inputs, 2024);

    $late = collect($result['items'])->first(fn($i) => $i['code'] === 'LATE');
    $this->assertNotNull($late);
    $this->assertEqualsWithDelta(125.0, abs((float) $late['amount']), 0.01);
}

public function test_ot_on_regular_holiday_pays_triple(): void
{
    $employee = $this->makeEmployee(26000, 'monthly');
    $inputs = new PayrollInputs(regularHolidayOtHours: 2);
    $result = $this->engine->computeForEmployee($employee, $inputs, 2024);

    $item = collect($result['items'])->first(fn($i) => $i['code'] === 'HOL_REG_OT');
    $this->assertNotNull($item);
    // Regular holiday = 200%, OT on top = 200% × 1.30 = 260% of hourly
    $this->assertEqualsWithDelta(125.0 * 2.60 * 2, (float) $item['amount'], 0.01);
}

public function test_loan_deduction_appears_in_payslip_items(): void
{
    $employee = $this->makeEmployee(30000, 'monthly');
    $inputs = new PayrollInputs(
        otherDeductions: [['code' => 'LOAN', 'label' => 'Salary Loan', 'amount' => 2000]]
    );
    $result = $this->engine->computeForEmployee($employee, $inputs, 2024);

    $loan = collect($result['items'])->first(fn($i) => $i['code'] === 'LOAN');
    $this->assertNotNull($loan);
    $this->assertSame(2000.0, abs((float) $loan['amount']));
}

public function test_net_pay_never_goes_negative(): void
{
    $employee = $this->makeEmployee(5000, 'monthly');
    $inputs = new PayrollInputs(
        otherDeductions: [['code' => 'BIG', 'label' => 'Huge Deduction', 'amount' => 99999]]
    );
    $result = $this->engine->computeForEmployee($employee, $inputs, 2024);

    $this->assertGreaterThanOrEqual(0.0, $result['summary']['net_pay']);
}
