```php
// Additions to ThirteenthMonthServiceTest.php

public function test_employee_with_no_payslips_gets_zero(): void
{
    $user = User::factory()->create();
    $employee = Employee::factory()->for($user)->create(['pay_frequency' => 'monthly']);

    $result = (new ThirteenthMonthService())->computeForEmployee($employee, 2024);

    $this->assertSame(0.0, $result['thirteenth_month']);
}

public function test_draft_payslips_are_excluded_from_basic_total(): void
{
    [$employee, $payslips] = $this->seedEmployeeWithPayslips(year: 2024, monthlyBasic: 30000, months: 3);
    // Add a draft payslip for month 4 — should NOT be included
    $draftPayslip = Payslip::factory()->for($employee)->create(['status' => 'draft', 'gross_earnings' => 30000]);
    PayslipItem::factory()->for($draftPayslip)->create(['code' => 'BASIC', 'amount' => 30000]);

    $result = (new ThirteenthMonthService())->computeForEmployee($employee, 2024);
    // Only 3 months of finalized payslips: 30k × 3 / 12 = 7,500
    $this->assertSame(7500.0, $result['thirteenth_month']);
}
