```php
// tests/Feature/Payroll/PayrollFullFlowTest.php
declare(strict_types=1);
namespace Tests\Feature\Payroll;

use App\Models\Employee;
use Illuminate\Foundation\Testing\RefreshDatabase;
use Tests\TestCase;
use Database\Seeders\{SssBracketSeeder, PhilhealthBracketSeeder, PagibigSettingSeeder, BirTaxBracketSeeder};

class PayrollFullFlowTest extends TestCase
{
    use RefreshDatabase;

    protected function setUp(): void
    {
        parent::setUp();
        $this->seed([SssBracketSeeder::class, PhilhealthBracketSeeder::class,
                     PagibigSettingSeeder::class, BirTaxBracketSeeder::class]);
    }

    public function test_full_payroll_cycle_create_run_finalize(): void
    {
        $admin = \App\Models\User::factory()->withRole('admin')->create();
        Employee::factory()->count(2)->create(['pay_frequency' => 'monthly', 'basic_salary' => 30000]);

        // Step 1: Create period
        $periodResp = $this->actingAs($admin, 'sanctum')->postJson('/api/v1/payroll/periods', [
            'name' => '2025-01', 'frequency' => 'monthly',
            'period_start' => '2025-01-01', 'period_end' => '2025-01-31',
        ])->assertCreated();
        $periodId = $periodResp->json('data.id');

        // Step 2: Create run
        $runResp = $this->actingAs($admin, 'sanctum')->postJson('/api/v1/payroll/runs', [
            'payroll_period_id' => $periodId, 'scope' => 'company',
        ])->assertCreated();
        $runId = $runResp->json('data.id');

        // Step 3: Payslips generated
        $this->actingAs($admin, 'sanctum')
             ->getJson("/api/v1/payroll/runs/{$runId}/payslips")
             ->assertOk()
             ->assertJsonCount(2, 'data');

        // Step 4: Finalize
        $this->actingAs($admin, 'sanctum')
             ->postJson("/api/v1/payroll/runs/{$runId}/finalize")
             ->assertOk()
             ->assertJsonPath('data.status', 'finalized');
    }

    public function test_finalized_period_blocks_new_run(): void
    {
        $admin = \App\Models\User::factory()->withRole('admin')->create();
        $period = \App\Models\PayrollPeriod::factory()->create(['status' => 'closed']);

        $this->actingAs($admin, 'sanctum')->postJson('/api/v1/payroll/runs', [
            'payroll_period_id' => $period->id, 'scope' => 'company',
        ])->assertUnprocessable();
    }
}
